task.output_schema:

# framework-validation-report.yaml

framework: "COOKIE"
validated_at: "{ISO-8601 timestamp}"
duration_seconds: {float}

summary:
  overall_status: "{PASS|FAIL}"
  total_checks: {int}
  passed: {int}
  warnings: {int}
  failed: {int}

by_category:
  - category: "Workflow Integrity"
    category_id: "WF"
    total: {int}
    passed: {int}
    warnings: {int}
    failed: {int}
  - category: "Slash Command Integrity"
    category_id: "CMD"
    total: {int}
    passed: {int}
    warnings: {int}
    failed: {int}
  - category: "Config Inheritance"
    category_id: "CFG"
    total: {int}
    passed: {int}
    warnings: {int}
    failed: {int}
  - category: "Pricing Coverage"
    category_id: "PRC"
    total: {int}
    passed: {int}
    warnings: {int}
    failed: {int}
  - category: "Resolution Profiles"
    category_id: "RES"
    total: {int}
    passed: {int}
    warnings: {int}
    failed: {int}
  - category: "Help CSV Coverage"
    category_id: "HLP"
    total: {int}
    passed: {int}
    warnings: {int}
    failed: {int}
  - category: "Manifest Integrity"
    category_id: "MAN"
    total: {int}
    passed: {int}
    warnings: {int}
    failed: {int}
  - category: "Schema Validation"
    category_id: "SCH"
    total: {int}
    passed: {int}
    warnings: {int}
    failed: {int}
  - category: "Path Resolution and Cross-References"
    category_id: "REF"
    total: {int}
    passed: {int}
    warnings: {int}
    failed: {int}

results:
  - rule_id: "{rule_id}"
    category: "{category_name}"
    name: "{rule name}"
    severity: "{error|warning}"
    status: "{pass|warn|fail}"
    details: "{description of findings}"
    affected_files: ["{file_path}", ...]
    auto_fix:
      available: {true|false}
      confidence: "{high|medium|low}"
      description: "{what the fix would do}"
      fix_action: "{specific action: add_row, remove_row, update_path, create_file, etc.}"
      fix_data: "{pre-filled data for the fix, e.g. CSV row content or corrected path}"

manifest_counts:
  agent_manifest:
    expected_rows: 13
    actual_rows: {int}
    status: "{pass|fail}"
  task_manifest:
    expected_rows: 10
    actual_rows: {int}
    status: "{pass|fail}"
  skill_manifest:
    expected_rows: 8
    actual_rows: {int}
    status: "{pass|fail}"

recommendations:
  - priority: "{high|medium|low}"
    rule_id: "{rule_id}"
    message: "{actionable recommendation}"
